// Extract task_id from the subject (survives Re:/Re: Re:) and clean the reply body.
// NOTE: quote/signature stripping is a known-fragile heuristic — fine for controlled test accounts.
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  const subject = j.subject || j.Subject || (j.headers && (j.headers.subject || j.headers.Subject)) || '';
  const m = String(subject).match(/#([A-Za-z0-9]+)/);
  if (!m) continue;
  const task_id = m[1];

  let body = j.text || j.textPlain || j.body || j.snippet || '';
  const lines = String(body).split(/\r?\n/);
  const kept = [];
  for (const line of lines) {
    const t = line.trim();
    if (/^On .*wrote:$/.test(t)) break;          // "On <date>, <name> wrote:"
    if (t.startsWith('>')) break;                 // quoted history
    if (/^-----Original Message-----/.test(t)) break;
    if (/^From:\s/.test(t)) break;                // forwarded header block
    kept.push(line);
  }
  let reply = kept.join('\n').trim();
  reply = reply.split(/\n-- \n/)[0].trim();       // strip signature after a '-- ' delimiter

  const from = j.from || (j.headers && j.headers.from) || '';
  const email = String(from).match(/[\w.+-]+@[\w.-]+\.[\w.-]+/);

  out.push({ json: {
    task_id,
    assignee_email: email ? email[0] : '',
    reply_text: reply,
    received_at: new Date().toISOString()
  }});
}
return out;
